sudo cp /etc/nginx/sites-enabled/default /etc/nginx/sites-enabled/default.backup && sudo sed -i '/# User\/Resort interface - \/resort routes/i \    # Orchid Admin Dashboard - \/orchidadmin routes\n    location \/orchidadmin {\n        alias \/var\/www\/resort\/Resort_first\/dasboard\/build;\n        try_files $uri $uri\/ \/orchidadmin\/index.html;\n\n        # Cache static assets\n        location ~* \\.(js|css|png|jpg|jpeg|gif|ico|svg)$ {\n            expires 1y;\n            add_header Cache-Control "public, immutable";\n        }\n    }\n\n    # Orchid admin dashboard static files\n    location \/orchidadmin-static\/ {\n        alias \/var\/www\/resort\/Resort_first\/dasboard\/build\/static\/;\n        expires 1y;\n        add_header Cache-Control "public, immutable";\n    }\n' /etc/nginx/sites-enabled/default && sudo nginx -t && sudo systemctl reload nginx && echo "✓ Nginx updated and reloaded successfully!"
